/** @deprecated Will be removed in a future version */
export interface Island {
  name: string;
  exportName: string;
  path: string;
  namedExport: boolean;
}

/** @deprecated Will be removed in a future version */
export type IslandsManifest = Record<string, Island | undefined>;

/**
 * Reads the islands manifest written by discoverNordicPages in `.nordic/discovery/`.
 * Returns undefined if the manifest has not been written yet.
 * @deprecated Will be removed in a future version
 */
export function getAllIslands(): IslandsManifest | undefined;

/**
 * Looks up an island by its absolute file path.
 * Returns undefined if no island matches the given path.
 * @param fullPath - Absolute file path of the island component
 * @deprecated Will be removed in a future version
 */
export function getIslandByFullPath(fullPath: string): Island | undefined;
